mapper.select:
SELECT
sd."MonitoringPointID" AS "monitoringPointID",
sd."SamplingDate"      AS "samplingDate",
sd."SoilAttribute"     AS "soilAttribute",
sd."Value"             AS "value"
FROM public."SoilDatas" sd
/* 如需：JOIN public."MonitoringPoints" mp
ON mp."MonitoringPointID" = sd."MonitoringPointID" */
WHERE sd."IsDelete" IS FALSE



    AND sd."SamplingDate" >= #{samplingDateFrom, jdbcType=TIMESTAMP}


    AND sd."SamplingDate" <  #{samplingDateTo, jdbcType=TIMESTAMP}




    AND sd."TobaccoFieldType" = #{tobaccoFieldType}


    AND sd."CountyDistrict" = #{countyDistrict}


    AND sd."Town" = #{town}


    AND sd."Village" = #{village}




    AND sd."SoilAttribute"::text IN

        #{a}



ORDER BY sd."MonitoringPointID", sd."SamplingDate"
